const { Client } = require('magicbell-js/project-client');
const broadcastModels = require('magicbell-js/dist/commonjs/project-client/services/broadcasts/models/broadcast.js');
const { z } = require('zod');

// Monkey-patch to avoid stripping un-modeled properties
broadcastModels.broadcastRequest = z.any();

async function test() {
  const client = new Client({
    token: process.env.MAGICBELL_PROJECT_TOKEN,
  });

  try {
    const { data } = await client.broadcasts.createBroadcast({
      title: "Test Broadcast",
      recipients: [{ email: process.env.MAGICBELL_EMAIL.replace('@', '+' + process.env.ZEALT_RUN_ID + '@') }],
      overrides: {
        channels: {
          email: {
            disable: true
          }
        }
      }
    });
    console.log("Success", data.id);
  } catch (e) {
    console.error("Error", e.response ? JSON.stringify(e.response.data) : e.message);
  }
}

test();

